import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import { logout } from './redux/slices/authSlice';
import Dashboard from './pages/Dashboard';
import Login from './pages/Login';
import Register from './pages/Register';
import { LogOut, CloudLightning, User, PlusCircle, LayoutDashboard } from 'lucide-react';

const NavLink = ({ to, children }) => {
  const location = useLocation();
  const isActive = location.pathname === to;
  return (
    <Link
      to={to}
      className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-200 ${
        isActive
          ? 'bg-white/15 text-white shadow-inner border border-white/10'
          : 'text-slate-400 hover:text-white hover:bg-white/8'
      }`}
    >
      {children}
    </Link>
  );
};

function AppInner() {
  const { token } = useSelector((state) => state.auth);
  const dispatch = useDispatch();

  return (
    <div className='min-h-screen bg-slate-950 font-sans text-white antialiased'>
      {/* ── Sticky glass navbar ── */}
      <header className='sticky top-0 z-50' style={{
        background: 'rgba(8, 12, 30, 0.72)',
        backdropFilter: 'blur(24px)',
        WebkitBackdropFilter: 'blur(24px)',
        borderBottom: '1px solid rgba(255,255,255,0.08)',
        boxShadow: '0 4px 30px rgba(0,0,0,0.4)'
      }}>
        <nav className='max-w-6xl mx-auto px-5 py-3.5 flex justify-between items-center'>

          {/* Logo */}
          <Link to='/' className='flex items-center gap-3 group select-none'>
            <div className='relative'>
              <div className='absolute inset-0 bg-indigo-500 rounded-xl blur-md opacity-50 group-hover:opacity-80 transition-opacity duration-300' />
              <div className='relative p-2.5 bg-gradient-to-br from-indigo-500 to-violet-600 rounded-xl shadow-lg'>
                <CloudLightning size={20} className='text-white' />
              </div>
            </div>
            <div className='flex flex-col leading-none'>
              <span className='text-lg font-black tracking-tight text-gradient'>
                Atmosphere
              </span>
              <span className='text-[10px] text-white/35 font-medium tracking-widest uppercase'>
                Weather Intelligence
              </span>
            </div>
          </Link>

          {/* Right side */}
          <div className='flex gap-2 items-center'>
            {token ? (
              <>
                <NavLink to='/'>
                  <span className='flex items-center gap-1.5'>
                    <LayoutDashboard size={14} />
                    Dashboard
                  </span>
                </NavLink>

                {/* Live indicator */}
                <div className='hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-xl'
                  style={{ background: 'rgba(34,197,94,0.1)', border: '1px solid rgba(34,197,94,0.2)' }}>
                  <span className='relative flex h-2 w-2'>
                    <span className='animate-ping-soft absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75'/>
                    <span className='relative inline-flex rounded-full h-2 w-2 bg-green-500'/>
                  </span>
                  <span className='text-xs font-semibold text-green-400'>Live</span>
                </div>

                <div className='hidden md:flex items-center gap-2 px-3 py-1.5 rounded-xl'
                  style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)' }}>
                  <User size={14} className='text-indigo-400' />
                  <span className='text-xs text-slate-300 font-medium'>Signed in</span>
                </div>

                <button
                  onClick={() => dispatch(logout())}
                  className='flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-200 active:scale-95'
                  style={{
                    background: 'rgba(239,68,68,0.1)',
                    border: '1px solid rgba(239,68,68,0.2)',
                    color: 'rgba(254,202,202,0.9)'
                  }}
                  onMouseEnter={e => { e.currentTarget.style.background = 'rgba(239,68,68,0.22)'; e.currentTarget.style.color = 'white'; }}
                  onMouseLeave={e => { e.currentTarget.style.background = 'rgba(239,68,68,0.1)'; e.currentTarget.style.color = 'rgba(254,202,202,0.9)'; }}
                >
                  <LogOut size={15} />
                  <span className='hidden sm:inline'>Logout</span>
                </button>
              </>
            ) : (
              <>
                <Link to='/login'
                  className='px-4 py-2 text-sm font-semibold text-slate-400 hover:text-white rounded-xl transition-all duration-200 hover:bg-white/8'
                >
                  Login
                </Link>
                <Link to='/register'
                  className='flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-bold text-white transition-all duration-300 active:scale-95'
                  style={{
                    background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
                    boxShadow: '0 4px 15px rgba(99,102,241,0.35)'
                  }}
                  onMouseEnter={e => { e.currentTarget.style.boxShadow = '0 8px 25px rgba(99,102,241,0.55)'; e.currentTarget.style.transform = 'translateY(-1px)'; }}
                  onMouseLeave={e => { e.currentTarget.style.boxShadow = '0 4px 15px rgba(99,102,241,0.35)'; e.currentTarget.style.transform = 'translateY(0)'; }}
                >
                  <PlusCircle size={15} />
                  <span>Sign Up</span>
                </Link>
              </>
            )}
          </div>
        </nav>
      </header>

      <main>
        <Routes>
          <Route path='/'         element={<Dashboard />} />
          <Route path='/login'    element={<Login />} />
          <Route path='/register' element={<Register />} />
        </Routes>
      </main>
    </div>
  );
}

function App() {
  return (
    <Router>
      <AppInner />
    </Router>
  );
}

export default App;
